SELECT 
    t.*,
    a.name as algorithm_name,
    CAST(t.dataset_id AS CHAR) as dataset_name,
    u.username as created_by_name
FROM algorithm_training t
LEFT JOIN algorithm a ON t.algorithm_id = a.id AND a.deleted = 0
LEFT JOIN sys_user u ON t.created_by = u.id AND u.deleted = 0
WHERE t.deleted = 0

    AND t.task_name LIKE CONCAT('%', #{taskName}, '%')


    AND t.algorithm_id = #{algorithmId}


    AND t.dataset_id = #{datasetId}


    AND t.train_status = #{trainStatus}


    AND t.created_by = #{createdBy}


    AND t.start_time >= #{startTimeBegin}


    AND t.start_time <= #{startTimeEnd}


    AND t.created_time >= #{createdTimeBegin}


    AND t.created_time <= #{createdTimeEnd}



        ORDER BY t.${orderBy} ${order}


        ORDER BY t.created_time DESC

SELECT 
FROM algorithm_training

    deleted = 0

        AND task_name like concat('%', #{taskName}, '%')


        AND algorithm_id = #{algorithmId}


        AND dataset_id = #{datasetId}


        AND train_status = #{trainStatus}


        AND created_by = #{createdBy}


ORDER BY created_time DESC

