UPDATE algorithm_training
task_name = #{taskName}, algorithm_id = #{algorithmId}, dataset_id = #{datasetId}, train_status = #{trainStatus}, progress = #{progress}, epoch_current = #{epochCurrent}, epoch_total = #{epochTotal}, accuracy = #{accuracy}, precision_value = #{precisionValue}, recall_value = #{recallValue}, map_value = #{mapValue}, loss_value = #{lossValue}, gpu_usage = #{gpuUsage}, start_time = #{startTime}, end_time = #{endTime}, estimated_time = #{estimatedTime}, model_output_path = #{modelOutputPath}, log_path = #{logPath}, config_params = #{configParams}, error_message = #{errorMessage}, updated_time = NOW(),
WHERE id = #{id}
